import sys

def shortest_palindrome(s):
    if len(s) == 0:
        return ""

    n = len(s)
    l, r = 0, n - 1
    while l <= r:
        if s[l] == s[r]:
            l += 1
            r -= 1
        else:
            break

    # If the entire string is a palindrome
    if l > r:
        return s

    # Otherwise, append the reverse of the remaining part
    return s + s[l:][::-1]

def main():
    s = sys.stdin.readline().strip()
    print(shortest_palindrome(s))

if __name__ == "__main__":
    main()
